+				root.SetArgs([]string{"completion", shell})
+				if err := root.Execute(); err != nil {
+					t.Fatalf("execute: %v", err)
+				}
+			})
+			if out == "" {
+				t.Fatalf("expected completion output")
+			}
+		})
+	}
+}

